  ('dietitian-moex-09036', 'dietitian', 'dietitian-moex-097-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '針對食品生產過程，包括從原料採收處理開始，經由加工、包裝、流通乃至最終產品提供消費者為止， 進行一科學化及系統化之評估分析整個過程，以了解各種潛在性危害發生之可能性及其危害程度。此過 程稱為：', '["危害分析（HA）", "重要管制點（CCP）", "HACCP制度的支持系統", "實施HACCP自主管理制度五項業者應有之認知"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "3f49438bcf6e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09037', 'dietitian', 'dietitian-moex-097-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '根據行政院衛生署建議學校午餐之主食應以米食為原則，每週至少供應多少天以上？', '["2天以上", "3天以上", "4天以上", "5天以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "3f49438bcf6e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
